const DEFAULT_IMAGE = 'https://i.imgur.com/6M3J4gG.gif';

/**
 * Normalizes an exercise name for filename matching (lowercase, underscores instead of spaces).
 */
const normalizeForFile = (name: string): string => {
  return name.toLowerCase().trim().replace(/\s+/g, '_');
};

/**
 * Returns the best available media for an exercise.
 * Checks for:
 * 1. Matching local video (provided via asset naming convention)
 * 2. Predefined Imgur GIF
 * 3. Default fallback GIF
 */
export const getImageForExercise = (name: string, availableVideos: string[] = []): string => {
    const normalized = normalizeForFile(name);

    // Check if we have a matching local video in our index
    // We expect the availableVideos to contain paths like "content/videos/diamond_pushups.mp4"
    if (availableVideos && availableVideos.length > 0) {
        const localVideo = availableVideos.find(v => v.toLowerCase().includes(normalized));
        if (localVideo) {
            return localVideo;
        }
    }

    return exerciseImageMap.get(name.toLowerCase().trim()) || DEFAULT_IMAGE;
};

export type AssetIndex = {
  images: string[];
  videos: string[];
  texts: string[];
  content: string[];
};

const emptyIndex: AssetIndex = {
  images: [],
  videos: [],
  texts: [],
  content: [],
};

export async function loadAssetIndex(): Promise<AssetIndex> {
  try {
    const response = await fetch('content/leanx_index.json', { cache: 'no-store' });
    if (!response.ok) {
      console.warn(`Asset index not found (status: ${response.status}). If you have local videos, ensure public/content/leanx_index.json exists.`);
      return emptyIndex;
    }
    const data = await response.json();
    if (data && (Array.isArray(data.images) || Array.isArray(data.videos))) {
       return {
           images: Array.isArray(data.images) ? data.images : [],
           videos: Array.isArray(data.videos) ? data.videos : [],
           texts: Array.isArray(data.texts) ? data.texts : [],
           content: Array.isArray(data.content) ? data.content : [],
       };
    }
    return emptyIndex;
  } catch (error) {
    console.warn('Error loading asset index. Defaulting to built-in GIFs.', error);
    return emptyIndex;
  }
}

export function isImage(path: string): boolean {
  return /\.(jpe?g|png|gif|webp|svg)$/i.test(path);
}

export function isVideo(path: string): boolean {
  return /\.(mp4|webm|mov|ogg)$/i.test(path);
}

export function isText(path: string): boolean {
  return /\.(txt|json|md|html|css|js)$/i.test(path);
}

