const generateVideoThumbnail = (videoSrc: string): Promise<string> => {
  return new Promise((resolve, reject) => {
    const video = document.createElement('video');
    video.src = videoSrc;
    video.crossOrigin = 'anonymous'; 

    const handleSeeked = () => {
      const canvas = document.createElement('canvas');
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const thumbnailUrl = canvas.toDataURL('image/jpeg', 0.8);
        cleanup();
        resolve(thumbnailUrl);
      } else {
        cleanup();
        reject(new Error('Could not get 2d context from canvas.'));
      }
    };

    const handleLoadedData = () => {
      video.currentTime = Math.min(1, video.duration / 2);
    };

    const handleError = () => {
      cleanup();
      reject(new Error('Failed to load video for thumbnail generation.'));
    };

    const cleanup = () => {
      video.removeEventListener('loadeddata', handleLoadedData);
      video.removeEventListener('seeked', handleSeeked);
      video.removeEventListener('error', handleError);
      video.remove();
    };

    video.addEventListener('loadeddata', handleLoadedData);
    video.addEventListener('seeked', handleSeeked);
    video.addEventListener('error', handleError);

    setTimeout(() => {
        if (video.readyState >= 2) { 
            handleLoadedData();
        }
    }, 200);
  });
};

const App: React.FC = () => {
    const [workouts, setWorkouts] = useState<Workout[]>([]);
    const [progress, setProgress] = useState<Progress>(() => ProgressService.loadProgress());
    const [profile, setProfile] = useState<Profile | null>(() => ProgressService.loadProfile());
    const [settings, setSettings] = useState<Settings>(() => ProgressService.loadSettings());
    const [customExercises, setCustomExercises] = useState<Exercise[]>(() => ProgressService.loadCustomExercises());
    const [availableVideos, setAvailableVideos] = useState<string[]>([]);
    const [sessionReps, setSessionReps] = useState<(number | null)[][]>([]);
    const [view, setView] = useState<AppView>(() => ProgressService.loadProfile() ? 'home' : 'onboarding');
    const [selectedWorkoutIndex, setSelectedWorkoutIndex] = useState<number | null>(null);
    const [modalExercise, setModalExercise] = useState<Exercise | null>(null);

    const [newProfilePicture, setNewProfilePicture] = useState<string | null>(null);
    const [tempOnboardingName, setTempOnboardingName] = useState<string>('');

    const [lastEarnedXp, setLastEarnedXp] = useState(0);
    const [isLevelUpEvent, setIsLevelUpEvent] = useState(false);
    const [currentStreak, setCurrentStreak] = useState(0);

    const [exerciseEditorData, setExerciseEditorData] = useState<Partial<Exercise>>({});
    const [originalExerciseNameForEdit, setOriginalExerciseNameForEdit] = useState<string | null>(null);

    const [imageToCrop, setImageToCrop] = useState<string | null>(null);
    const [returnToView, setReturnToView] = useState<AppView>('home');
    const [videoForThumbnailSelection, setVideoForThumbnailSelection] = useState<string | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const isInitialLoad = useRef(true);
    const [isWakeLockSupported, setIsWakeLockSupported] = useState(true);

    const selectedWorkout = selectedWorkoutIndex !== null ? workouts[selectedWorkoutIndex] : null;

    // Load local asset index to see which videos we actually have
    useEffect(() => {
        loadAssetIndex().then(index => {
            if (index && index.videos) {
                setAvailableVideos(index.videos);
            }
        });
    }, []);

    useEffect(() => {
        const checkWakeLockSupport = () => {
            const supported = 'wakeLock' in navigator;
            setIsWakeLockSupported(supported);

            if (!supported) {
                setSettings(currentSettings => {
                    if (currentSettings.enableWakeLock) {
                        const newSettings = { ...currentSettings, enableWakeLock: false };
                        ProgressService.saveSettings(newSettings);
                        return newSettings;
                    }
                    return currentSettings;
                });
            }
        };
        checkWakeLockSupport();
    }, []);

    useEffect(() => {
        const customExercisesMap = new Map<string, Exercise>(customExercises.map(ex => [ex.name.toLowerCase(), ex] as [string, Exercise]));

        const createExerciseWithOverrides = (name: string): Exercise => {
            const custom = customExercisesMap.get(name.toLowerCase());
            if (custom) return custom;

            // 1. Check for Local Video File
            const mediaSource = getImageForExercise(name, availableVideos);
            const isLocalVideo = mediaSource.toLowerCase().endsWith('.mp4') || mediaSource.toLowerCase().endsWith('.webm');

            // 2. Check for YouTube ID (if no local video found or if specific override desired)
            // Note: If a local video exists (isLocalVideo is true), we prefer that. 
            // If not, we check for a YouTube ID.
            const youtubeId = !isLocalVideo ? getYoutubeIdForExercise(name) : undefined;

            // 3. Determine Image/Thumbnail
            // If YouTube, use YouTube thumbnail. If local video, leave empty (or implement thumbnail gen). If GIF, use it.
            let image = mediaSource;
            if (youtubeId) {
                image = `https://img.youtube.com/vi/${youtubeId}/hqdefault.jpg`;
            } else if (isLocalVideo) {
                image = ''; // Could generate thumbnail, or fallback to GIF if available?
                // Currently getImageForExercise returns the video path if found, or the GIF if not.
                // If it returns a video path, we don't have a static image unless we generate one.
                // For simplicity, we can let the video element handle the poster or just show the video.
            }

            return {
                name,
                image: image, 
                video: isLocalVideo ? mediaSource : undefined,
                youtubeId: youtubeId,
                description: [
                    'Maintain a straight back and engaged core.',
                    'Focus on controlled, deliberate movements.',
                    'Breathe steadily throughout the exercise.'
                ]
            };
        };

        const dataWithOverrides = WORKOUT_NAMES.map(w => {
            const { work, rest, rounds } = parseTiming(w.timing, w.rounds);
            const id = `${w.cycle}|${w.week}|${w.day}|${w.timing}`.toLowerCase();

            return {
                cycle: w.cycle,
                week: w.week,
                day: w.day,
                timing: w.timing,
                id,
                work,
                rest,
                rounds,
                preWarmUp: createExerciseWithOverrides(w.preWarmUp),
                warmUp: createExerciseWithOverrides(w.warmUp),
                warmUpExercises: (w.warmUp === 'Crawling Warm Up' ? CRAWLING_WARMUP_NAMES : SIDELYING_WARMUP_NAMES).map(createExerciseWithOverrides),
                exercises: w.exercises.map(createExerciseWithOverrides),
                coolDown: createExerciseWithOverrides(w.coolDown),
            };
        }).filter(assertWorkout);

        setWorkouts(dataWithOverrides);
    }, [customExercises, availableVideos]);

    useEffect(() => {
        if (!ProgressService.loadProfile() || workouts.length === 0) return;

        if (!isInitialLoad.current) return;

        isInitialLoad.current = false;

        let resumeWorkoutIndex = -1;
        const progressWithKeys = Object.entries(progress);
        const inProgressEntry = progressWithKeys.find(([,p]) => (p as ProgressItem).inProgress && (p as ProgressItem).snap);

        if (inProgressEntry) {
            const workoutIdToResume = (inProgressEntry[1] as ProgressItem).snap?.workoutId;
            if (workoutIdToResume) {
                const foundIndex = workouts.findIndex(w => w.id === workoutIdToResume);
                if (foundIndex !== -1) {
                    resumeWorkoutIndex = foundIndex;
                } else {
                    console.warn(`Workout to resume (id: ${workoutIdToResume}) not found. Clearing state.`);
                    ProgressService.clearInProgress(inProgressEntry[0]);
                }
            }
        }

        if (resumeWorkoutIndex !== -1) {
            setSelectedWorkoutIndex(resumeWorkoutIndex);
            setView('workout');
        } else {
            const p = ProgressService.loadProfile();
            if (p) {
                const firstNotDone = workouts.findIndex((w) => !progress[ProgressService.getWorkoutUID(w)]?.done);
                const firstOfLevel = workouts.findIndex(w => w.cycle === p.difficulty);

                if (firstNotDone >= 0) {
                     setSelectedWorkoutIndex(firstNotDone);
                } else if (firstOfLevel >= 0) {
                    setSelectedWorkoutIndex(firstOfLevel);
                } else {
                    setSelectedWorkoutIndex(0);
                }
            }
        }
    }, [workouts, progress]);

    const handleSelectWorkout = useCallback((index: number) => {
        setSelectedWorkoutIndex(index);
    }, []);

    const handleUpdateProgress = (newProgress: Progress) => {
        setProgress(newProgress);
    };

    const handleStartWorkout = () => {
        if (selectedWorkout) {
            const repsForWorkout = Array(selectedWorkout.exercises.length).fill(0).map(() => Array(selectedWorkout.rounds).fill(null));
            setSessionReps(repsForWorkout);
            setView('workout');
        }
    };

    const handleWorkoutFinish = useCallback(() => {
        if (selectedWorkout) {
            const uid = ProgressService.getWorkoutUID(selectedWorkout);
            const newProgress = ProgressService.markDone(uid);
            setProgress(newProgress);

            const statsUpdate = ProgressService.updateProfileStats(selectedWorkout);
            if (statsUpdate) {
                setProfile(statsUpdate.profile);
                setLastEarnedXp(statsUpdate.xpGained);
                setIsLevelUpEvent(statsUpdate.levelUp);
                setCurrentStreak(statsUpdate.profile.stats?.currentStreak || 0);
            }
        }
        setView('finished');
    }, [selectedWorkout]);

    const handleLogReps = () => {
        setView('repTracking');
    };

    const handleReturnToHomeWithNextWorkout = () => {
        if (selectedWorkoutIndex !== null) {
            const nextIndex = (selectedWorkoutIndex + 1) % workouts.length;
            setSelectedWorkoutIndex(nextIndex);
        } else {
            const firstNotDone = workouts.findIndex((w) => !progress[ProgressService.getWorkoutUID(w)]?.done);
            setSelectedWorkoutIndex(firstNotDone >= 0 ? firstNotDone : 0);
        }
        setView('home');
    };

    const handleContinueFromFinish = () => {
        handleReturnToHomeWithNextWorkout();
    };

    const handleSaveReps = (reps: number[]) => {
        if (selectedWorkout) {
            const uid = ProgressService.getWorkoutUID(selectedWorkout);
            const newProgress = ProgressService.saveRepsForWorkout(uid, reps);
            setProgress(newProgress);
        }
        handleReturnToHomeWithNextWorkout();
    };

    const handleImageSelected = (dataUrl: string) => {
        if (returnToView === 'exerciseEditor') {
            setExerciseEditorData(prev => ({ ...prev, image: dataUrl, video: undefined, youtubeId: undefined }));
            setView('exerciseEditor');
        } else {
            setImageToCrop(dataUrl);
            setView('imageCropper');
        }
    };

    const handleVideoSelected = async (videoDataUrl: string) => {
        try {
            const thumbnailUrl = await generateVideoThumbnail(videoDataUrl);
            setExerciseEditorData(prev => ({ ...prev, image: thumbnailUrl, video: videoDataUrl, youtubeId: undefined }));
        } catch (e) {
            console.error("Thumbnail generation failed:", e);
            setExerciseEditorData(prev => ({ ...prev, image: undefined, video: videoDataUrl, youtubeId: undefined }));
        }
        setView(returnToView);
    };

    const handleCropComplete = (croppedDataUrl: string | null) => {
        if (croppedDataUrl) {
            if (returnToView === 'profile' && profile) {
                const updatedProfile = { ...profile, picture: croppedDataUrl };
                setProfile(updatedProfile);
                ProgressService.saveProfile(updatedProfile);
            } else if (returnToView === 'onboarding') {
                 setNewProfilePicture(croppedDataUrl);
            }
        }
        setView(returnToView);
        setImageToCrop(null);
    };

    const handleCreateProfile = (newProfile: Profile) => {
        ProgressService.saveProfile(newProfile);
        setProfile(newProfile);
        setTempOnboardingName('');
        setNewProfilePicture(null);

        const firstWorkoutOfLevel = workouts.findIndex(w => w.cycle === newProfile.difficulty);
        if (firstWorkoutOfLevel >= 0) {
            setSelectedWorkoutIndex(firstWorkoutOfLevel);
        } else {
            setSelectedWorkoutIndex(0);
        }
        setView('home');
    };

    const handleUpdateProfile = (updatedProfile: Profile) => {
        setProfile(updatedProfile);
        ProgressService.saveProfile(updatedProfile);
    };

    const handleUpdateSettings = (newSettings: Settings) => {
        setSettings(newSettings);
        ProgressService.saveSettings(newSettings);
    };

    const handleUpsertExercise = () => {
        const exercise: Exercise = {
            name: exerciseEditorData.name!,
            image: exerciseEditorData.image!,
            description: exerciseEditorData.description || [],
            video: exerciseEditorData.video,
            youtubeId: exerciseEditorData.youtubeId,
        };
        const newCustomExercises = ProgressService.addCustomExercise(exercise);
        setCustomExercises(newCustomExercises);
        setExerciseEditorData({});
        setOriginalExerciseNameForEdit(null);
        setView('tutorial');
    };

    const handleThumbnailSelected = (dataUrl: string) => {
        setExerciseEditorData(prev => ({ ...prev, image: dataUrl }));
        setVideoForThumbnailSelection(null);
        setView('exerciseEditor');
    };

    const handleBack = () => {
        if (view === 'workout' && selectedWorkout) {
            const uid = ProgressService.getWorkoutUID(selectedWorkout);
            const newProgress = ProgressService.clearInProgress(uid);
            setProgress(newProgress);
            setView('home');
        } else if (view === 'repTracking') {
             setView('finished');
        } else if (['profile', 'tutorial', 'chooseCycle', 'settings', 'camera', 'imageCropper', 'exerciseEditor', 'videoRecorder', 'thumbnailSelector', 'videoMatcher'].includes(view)) {
             if (view === 'camera' || view === 'imageCropper' || view === 'videoRecorder') {
                setView(returnToView);
             } else if (view === 'exerciseEditor') {
                setView('tutorial');
             } else if (view === 'thumbnailSelector') {
                setView('exerciseEditor');
             } else if (view === 'videoMatcher') {
                setView('settings');
             } else {
                setView('home');
             }
        } else {
            setView('home');
        }
    };

    const handleSaveAndExitWorkout = () => {
        setView('home');
    };

    const BottomNavBar = () => {
        const navItems = [
            { view: 'home', icon: HomeIcon, label: 'Home' },
            { view: 'chooseCycle', icon: BookIcon, label: 'Plan' },
            { view: 'profile', icon: UserIcon, label: 'Profile' },
            { view: 'settings', icon: SettingsIcon, label: 'Settings' },
        ];

        return (
            <footer className="fixed bottom-0 left-0 right-0 bg-black/90 backdrop-blur-xl border-t border-white/10 z-20 pb-safe">
                <nav className="flex justify-around items-center h-16">
                    {navItems.map(item => (
                        <button
                            key={item.view}
                            onClick={() => setView(item.view as AppView)}
                            className={`flex flex-col items-center justify-center w-full h-full transition-colors ${
                                view === item.view ? 'text-accent' : 'text-gray-500 hover:text-gray-300'
                            }`}
                            aria-label={item.label}
                        >
                            <item.icon className="w-6 h-6" />
                            <span className="text-[10px] mt-1 font-bold uppercase tracking-wider">{item.label}</span>
                        </button>
                    ))}
                </nav>
            </footer>
        );
    };

    const renderView = () => {
        switch (view) {
            case 'onboarding':
                return (
                    <OnboardingWizard 
                        initialName={tempOnboardingName}
                        onComplete={handleCreateProfile}
                        onTakePhoto={(currentName) => { 
                            setTempOnboardingName(currentName);
                            setReturnToView('onboarding'); 
                            setView('camera'); 
                        }}
                        onFromGallery={() => { setReturnToView('onboarding'); fileInputRef.current?.click(); }}
                        tempPicture={newProfilePicture}
                    />
                );
            case 'camera':
                return (
                    <CameraView 
                        onPictureTaken={handleImageSelected} 
                        onCancel={() => setView(returnToView)} 
                    />
                );
            case 'videoRecorder':
                return (
                    <VideoRecorder
                        onVideoTaken={handleVideoSelected}
                        onCancel={() => setView(returnToView)}
                    />
                );
            case 'imageCropper':
                if (imageToCrop) {
                    return <ImageCropper 
                        src={imageToCrop} 
                        onComplete={handleCropComplete} 
                        onCancel={() => {
                            setView(returnToView);
                            setImageToCrop(null);
                        }} 
                    />
                }
                setView(returnToView);
                return null;
            case 'thumbnailSelector':
                if (videoForThumbnailSelection) {
                    return <ThumbnailSelector
                        src={videoForThumbnailSelection}
                        onComplete={handleThumbnailSelected}
                        onCancel={handleBack}
                    />
                }
                setView('exerciseEditor');
                return null;
            case 'exerciseEditor':
                return <ExerciseEditorScreen
                    exerciseData={exerciseEditorData}
                    onDataChange={setExerciseEditorData}
                    originalName={originalExerciseNameForEdit}
                    onBack={handleBack}
                    onSave={handleUpsertExercise}
                    onTakePhoto={() => {
                        setReturnToView('exerciseEditor');
                        setView('camera');
                    }}
                    onRecordVideo={() => {
                        setReturnToView('exerciseEditor');
                        setView('videoRecorder');
                    }}
                    onSelectThumbnail={() => {
                        if (exerciseEditorData.video) {
                            setVideoForThumbnailSelection(exerciseEditorData.video);
                            setView('thumbnailSelector');
                        }
                    }}
                    onChooseFromGallery={() => {
                        setReturnToView('exerciseEditor');
                        fileInputRef.current?.click();
                    }}
                />;
            case 'videoMatcher':
                return <VideoMatcher onBack={handleBack} />;
            case 'workout':
                if (selectedWorkout) {
                    return <WorkoutScreen 
                        workout={selectedWorkout} 
                        settings={settings}
                        onUpdateSettings={handleUpdateSettings}
                        sessionReps={sessionReps}
                        setSessionReps={setSessionReps}
                        onBack={handleBack} 
                        onFinish={handleWorkoutFinish}
                        onShowExerciseInfo={setModalExercise}
                        onSaveAndExit={handleSaveAndExitWorkout}
                        isWakeLockSupported={isWakeLockSupported}
                    />;
                }
                return null;
            case 'finished':
                return <FinishedScreen 
                    onLogReps={handleLogReps} 
                    onContinue={handleContinueFromFinish} 
                    earnedXp={lastEarnedXp}
                    isLevelUp={isLevelUpEvent}
                    streak={currentStreak}
                />;
            case 'repTracking':
                if (selectedWorkout) {
                    const summedReps = sessionReps.map(exerciseReps => 
                        exerciseReps.reduce((acc, rep) => acc + (rep || 0), 0)
                    );
                    return <RepTrackingScreen 
                        workout={selectedWorkout} 
                        onSaveReps={handleSaveReps} 
                        onBack={handleBack} 
                        initialReps={summedReps}
                    />;
                }
                return null;
            case 'profile':
                 if (profile) {
                    return <ProfileScreen 
                        profile={profile} 
                        progress={progress} 
                        workouts={workouts} 
                        onUpdateProfile={handleUpdateProfile}
                        onBack={handleBack}
                        onTakePhoto={() => {
                            setReturnToView('profile');
                            setView('camera');
                        }}
                        onChooseFromGallery={() => {
                            setReturnToView('profile');
                            fileInputRef.current?.click();
                        }}
                    />;
                 }
                 setView('onboarding'); 
                 return null;
            case 'tutorial':
                return <TutorialScreen
                    onSelectExercise={setModalExercise}
                    onBack={handleBack}
                    onCreateNew={() => {
                        setExerciseEditorData({ name: '', description: [], image: '', video: undefined, youtubeId: undefined });
                        setOriginalExerciseNameForEdit(null);
                        setView('exerciseEditor');
                    }}
                    onEditExercise={(exercise) => {
                        setExerciseEditorData(exercise);
                        setOriginalExerciseNameForEdit(exercise.name);
                        setView('exerciseEditor');
                    }}
                    customExercises={customExercises}
                />
            case 'settings':
                return <SettingsScreen
                    settings={settings}
                    onUpdateSettings={handleUpdateSettings}
                    onBack={handleBack}
                    isWakeLockSupported={isWakeLockSupported}
                    onOpenVideoMatcher={() => setView('videoMatcher')}
                />;
            case 'chooseCycle':
                return (
                    <div className="min-h-screen flex flex-col p-4">
                        <header className="flex items-center mb-6">
                            <button onClick={handleBack} className="p-2 -ml-2">
                                <BackArrowIcon className="w-6 h-6" />
                            </button>
                            <h1 className="font-bold text-xl mx-auto uppercase tracking-wider">Select Workout</h1>
                            <div className="w-6 h-6"></div>
                        </header>
                        <main className="flex-grow overflow-y-auto">
                            <History
                                workouts={workouts}
                                progress={progress}
                                onSelectWorkout={(index) => {
                                    handleSelectWorkout(index);
                                    setView('home');
                                }}
                                onUpdateProgress={handleUpdateProgress}
                                selectedWorkoutIndex={selectedWorkoutIndex}
                            />
                        </main>
                    </div>
                );
            case 'home':
            default:
                const uid = selectedWorkout
                    ? ProgressService.getWorkoutUID(selectedWorkout)
                    : null;
                const lastResult = uid ? progress[uid] : undefined;

                return (
                    <div className="p-4 space-y-6 min-h-screen flex flex-col">
                        <div className="flex justify-center items-center py-6">
                            <h1 className="text-4xl font-black italic tracking-tighter">LEAN<span className="text-accent">X</span></h1>
                        </div>

                        {selectedWorkout && (
                            <PreviewScreen
                                workout={selectedWorkout}
                                onStart={handleStartWorkout}
                                lastResult={lastResult}
                            />
                        )}

                        <div className="mt-auto pt-4">
                            <button 
                                onClick={() => setView('chooseCycle')} 
                                className="w-full bg-gray-900/80 backdrop-blur-md text-gray-400 font-bold py-4 rounded-2xl text-sm uppercase tracking-widest border border-dashed border-gray-700 hover:border-accent hover:text-accent transition-all"
                            >
                                Choose Workout
                            </button>
                        </div>
                    </div>
                );
        }
    };

    const showNavBar = ['home', 'chooseCycle', 'tutorial', 'profile', 'settings'].includes(view);

    return (
        <main className={`min-h-screen bg-black text-white font-sans ${showNavBar ? 'pb-24' : ''} selection:bg-accent selection:text-black`}>
            <div className="fixed inset-0 bg-gradient-to-br from-gray-900 via-black to-gray-900 pointer-events-none z-[-1]"></div>

            <input
                type="file"
                ref={fileInputRef}
                onChange={(e) => {
                    const file = e.target.files?.[0];
                    if (file) {
                        if (file.type.startsWith('image/')) {
                            const reader = new FileReader();
                            reader.onload = (event) => {
                                const img = document.createElement('img');
                                img.onload = () => {
                                    const MAX_DIMENSION = 800;
                                    let { width, height } = img;

                                    if (width > MAX_DIMENSION || height > MAX_DIMENSION) {
                                        if (width > height) {
                                            height = Math.round((height * MAX_DIMENSION) / width);
                                            width = MAX_DIMENSION;
                                        } else {
                                            width = Math.round((width * MAX_DIMENSION) / height);
                                            height = MAX_DIMENSION;
                                        }
                                    }

                                    const canvas = document.createElement('canvas');
                                    canvas.width = width;
                                    canvas.height = height;
                                    const ctx = canvas.getContext('2d');
                                    if (ctx) {
                                        ctx.drawImage(img, 0, 0, width, height);
                                        const dataUrl = canvas.toDataURL('image/jpeg', 0.9);
                                        handleImageSelected(dataUrl);
                                    }
                                };
                                img.src = event.target?.result as string;
                            };
                            reader.readAsDataURL(file);
                        } else if (file.type.startsWith('video/')) {
                            const reader = new FileReader();
                            reader.onload = (event) => {
                                const videoDataUrl = event.target?.result as string;
                                if (videoDataUrl) {
                                    handleVideoSelected(videoDataUrl);
                                }
                            };
                            reader.readAsDataURL(file);
                        }
                    }
                    e.target.value = '';
                }}
                accept="image/*,video/*"
                className="hidden"
            />
            {renderView()}
            {modalExercise && (
                <ExerciseDetailModal 
                    exercise={modalExercise}
                    onClose={() => setModalExercise(null)}
                />
            )}
            {showNavBar && <BottomNavBar />}
        </main>
    );
};

export default App;

payload.text:
Hier ist das Audit und die Release-Roadmap für die Transformation von **LeanX** zu einer nativen Android-App.

### A) Executive Summary

1.  **Technologie-Entscheidung:** **Capacitor** ist der einzig logische Weg. Du hast eine responsive React-App (Vite/Tailwind). Ein Rewrite in Flutter/React Native wäre unwirtschaftlich (Aufwand > Nutzen). Capacitor wickelt deine Web-App in einen nativen Container und gibt dir Zugriff auf Kamera, Dateisystem und WakeLock.
2.  **Kritisches Risiko (Datenverlust):** Du nutzt aktuell `localStorage` (`services/progressService.ts`). **Android löscht localStorage**, wenn der Speicher knapp wird. Das muss zwingend auf `@capacitor/preferences` oder `@capacitor/filesystem` umgestellt werden, sonst verlieren Nutzer ihren Fortschritt.
3.  **Kritisches Risiko (Timer):** JavaScript-Timer (`setInterval` in `hooks/useTimer.ts`) stoppen oder verlangsamen sich, wenn die App in den Hintergrund geht oder der Bildschirm ausgeht. Du benötigst eine Logik, die die verstrichene Zeit beim "Aufwachen" ("Resume") neu berechnet, oder ein natives Background-Plugin.
4.  **Hardware-Integration:** Die aktuellen HTML5-Inputs für Kamera/Video (`<input type="file">` & `navigator.mediaDevices`) fühlen sich in einer App "fremd" an. Hier sollten die nativen Capacitor-Plugins für eine flüssige UX (Permissions, Galerie-Zugriff) genutzt werden.
5.  **UX-Lücken:** Es fehlt die Behandlung des **Hardware-Zurück-Buttons** von Android. Ohne diesen Handler schließt sich die App sofort, statt einen Screen zurückzugehen. Das führt zu App-Store-Ablehnungen oder frustrierten Nutzern.

---

### B) Priorisierte Roadmap

| Prio | Phase | Feature / Aufgabe | Aufwand | Warum? |
| :--- | :--- | :--- | :--- | :--- |
| **P0** | **Core Foundation** | **Capacitor Integration:** Init, Android-Platform Add, Icons/Splash Screen generieren. | **S** | Basis für die APK. |
| **P0** | **Stabilität** | **Storage Migration:** Umbau von `localStorage` auf Async Storage (Capacitor Preferences). | **M** | Verhindert Datenverlust (No-Go Fehler). |
| **P0** | **UX Hygiene** | **Hardware Back-Button:** Handling in `App.tsx` integrieren. | **S** | Erwartetes Android-Verhalten. |
| **P0** | **Funktion** | **Wake Lock & Timer Fix:** Native WakeLock Plugin & "Resume"-Logik für den Timer. | **M** | Damit der Timer nicht ausgeht/stoppt. |
| **P1** | **Experience** | **Native Camera/Filesystem:** Ersatz der HTML5 APIs durch `@capacitor/camera`. | **M** | Bessere Performance & UX bei Fotos/Videos. |
| **P1** | **Retention** | **Lokale Benachrichtigungen:** Erinnerung an Workouts (z.B. "Cycle complete"). | **S** | Erhöht Wiederkehrrate. |
| **P2** | **Polish** | **Haptisches Feedback:** Vibration bei Timer-Ablauf/Buttons. | **S** | Fühlt sich "echter" an. |
| **P2** | **Design** | **Safe Area Insets:** Anpassung für Notches/Statusbars (Edge-to-Edge). | **S** | Moderner Look. |

---

### C) Konkrete Code-/Architektur-Änderungen

#### 1. Storage Adapter (P0 - Wichtig!)
Der aktuelle `progressService.ts` ist synchron (`return JSON.parse(...)`). Capacitor Storage ist asynchron (`await ...`).
**Lösung:** Baue einen Zwischenlayer oder stelle die App auf asynchrones Laden um (z.B. `useEffect` beim Start).

*Pseudocode Änderung `services/storageAdapter.ts`:*
```typescript
import { Preferences } from '@capacitor/preferences';

// Statt localStorage.getItem('key')
export const getItem = async <T>(key: string): Promise<T | null> => {
  const { value } = await Preferences.get({ key });
  return value ? JSON.parse(value) : null;
};

// Statt localStorage.setItem('key', val)
export const setItem = async (key: string, value: any): Promise<void> => {
  await Preferences.set({ key, value: JSON.stringify(value) });
};
```
*Du musst dann deine `App.tsx` so umbauen, dass sie beim Start einen "Loading"-Screen zeigt, bis die Daten aus dem asynchronen Speicher geladen sind.*

#### 2. Hardware Back Button (P0)
In `App.tsx` (oder einem neuen `useBackHandler.ts` Hook):

```typescript
import { App as CapApp } from '@capacitor/app';

// Innerhalb deiner App-Component:
useEffect(() => {
  CapApp.addListener('backButton', ({ canGoBack }) => {
    if (view !== 'home') {
      // Wenn wir nicht auf Home sind: Gehe intern zurück
      handleBack(); 
    } else {
      // Wenn wir auf Home sind: App minimieren
      CapApp.minimizeApp();
    }
  });
}, [view, handleBack]); // Abhängigkeiten beachten!
```

#### 3. Timer-Korrektur (Background Throttling) (P0)
In `hooks/useTimer.ts`: JavaScript-Timer pausieren im Hintergrund.
**Lösung:** Speichere den Timestamp beim Verlassen und berechne die Differenz beim Wiederkehren.

```typescript
// Pseudocode Ergänzung in useTimer.ts
useEffect(() => {
  const handleResume = () => {
    const now = Date.now();
    const lastActive = parseInt(localStorage.getItem('lastActive') || '0');
    const diffSeconds = Math.floor((now - lastActive) / 1000);

    if (running && diffSeconds > 0) {
      setSeconds(prev => Math.max(0, prev - diffSeconds));
      // Ggf. Phasen überspringen, wenn diffSeconds > seconds
    }
  };

  const handlePause = () => {
    localStorage.setItem('lastActive', Date.now().toString());
  };

  document.addEventListener('resume', handleResume); // Cordova/Capacitor Event
  document.addEventListener('pause', handlePause);

  return () => { /* remove listeners */ };
}, [running]);
```

---

### D) UI/UX To-do Liste (Material 3 & Mobile)

1.  **Safe Areas (Notch Support):**
    *   Füge in `index.html` im `<meta name="viewport">` hinzu: `viewport-fit=cover`.
    *   Nutze in Tailwind Utility-Klassen: `pt-[env(safe-area-inset-top)]` für Header und `pb-[env(safe-area-inset-bottom)]` für die Nav-Bar.
    *   *Status:* Aktuell hast du `pb-safe` in der Nav-Bar (gut!), aber der Header (`SettingsScreen`, `ProfileScreen`) klebt oft oben am Rand (`top-0`). Hier muss Padding hin, sonst liegt die Notch über dem Text.
2.  **Touch Targets:**
    *   Prüfung: Die Buttons im `RepTrackingScreen` (Numpad) sind gut.
    *   Problem: Die "Back"-Pfeile (`BackArrowIcon`) haben oft nur kleines Padding.
    *   *Fix:* Mach die Klickfläche größer (min 48x48px), auch wenn das Icon klein bleibt.
3.  **Haptik:**
    *   Installiere `@capacitor/haptics`.
    *   Trigger: Kurzes `Haptics.impact({ style: ImpactStyle.Light })` beim Drücken von Buttons.
    *   Trigger: `Haptics.vibrate()` wenn der Timer (3-2-1) piept. Das verstärkt das "Taktische" Gefühl massiv.

---

### E) Behavioral Layer (Retention & Ethik)

**Ziel:** Nutzer sollen die App täglich öffnen (Streak) und Workouts beenden.

1.  **Feature: "Pre-Commitment" (Commitment Bias)**
    *   *Trigger:* Nach dem Klick auf "Finish" im `FinishedScreen`.
    *   *UI:* Kleines Modal/Button: "Plan next mission: [Tomorrow 08:00]".
    *   *Action:* Setzt eine lokale Notification.
    *   *Psychologie:* Wer jetzt zusagt, bricht sein Wort morgen seltener.

2.  **Feature: "Streak Freeze" (Loss Aversion)**
    *   *Trigger:* Nutzer verpasst einen Tag.
    *   *Logic:* Gib dem Nutzer *einen* "Joker" pro Woche.
    *   *Reward:* Wenn der Nutzer sieht "Streak gerettet", entsteht Dankbarkeit und erneute Motivation, statt Frust ("Jetzt ist eh alles egal").

3.  **Messplan (KPIs):**
    *   **Activation Rate:** % der Installs, die das erste Workout beenden.
    *   **Week 4 Retention:** Wer erreicht das "Advanced" Cycle?
    *   **A/B Test:** Teste im `PreviewScreen` den Button-Text: "Start Workout" vs. "Start Mission". (Hypothese: "Mission" passt besser zum taktischen Wording und erhöht CTR).

---

### F) Play Store Checklist (Compliance)

1.  **App Bundle (.aab):** Lade keine APK hoch, sondern ein Android App Bundle (optimierte Größe).
2.  **Signing Key:** Erstelle einen Upload-Keystore und verliere ihn **NIEMALS**. Speichere Passwörter im Passwortmanager.
3.  **Permissions Minimierung:**
    *   In `metadata.json` forderst du `microphone`. Prüfe: Brauchst du das wirklich für Videoaufnahmen *innerhalb* der App? Wenn ja, musst du im Play Store eine Erklärung abgeben. Wenn du nur Fotos machst: Entferne es.
    *   `camera`: Muss durch eine Privacy Policy abgedeckt sein.
4.  **Privacy Policy URL:** Du brauchst eine Webseite (kann eine einfache GitHub Page sein), die erklärt, dass Daten nur lokal auf dem Gerät gespeichert werden. Ohne URL kein Release.
5.  **Target API Level:** Stelle sicher, dass in `android/variables.gradle` (wird von Capacitor erstellt) das `targetSdkVersion` auf dem aktuellsten Stand (mind. 34) ist.
6.  **Google Play Data Safety Form:**
    *   Collection: No.
    *   Sharing: No.
    *   (Da alles lokal ist, ist dieses Formular sehr einfach auszufüllen).

